+
+	if len(result.MetadataReset) > 0 {
+		fmt.Printf("\n  Metadata reset for: %s\n", strings.Join(result.MetadataReset, ", "))
+	}
+
+	// Validate restored state
+	fmt.Println("\nValidating restored state...")
